const headers = $json.headers || {};
const body = $json.body || {};

const getHeader = (name) => {
  const key = Object.keys(headers).find((k) => k.toLowerCase() === name.toLowerCase());
  return key ? headers[key] : '';
};

const event = String(getHeader('x-github-event') || '').toLowerCase();
const deliveryId = String(getHeader('x-github-delivery') || '').trim();
const action = body.action || '';
const repo = body.repository?.full_name || 'repo/desconocido';
const repoName = body.repository?.name || '';
const actor = body.sender?.login || body.pusher?.name || 'desconocido';
const backendRepo = 'PetSafe-Back';
const frontendRepo = 'PetSafe-Front';

let repoScope = 'github';
if (repoName && repoName === backendRepo) repoScope = 'backend';
else if (repoName && repoName === frontendRepo) repoScope = 'frontend';

let ignored = false;
let tipo = 'github_evento';
let titulo = 'Evento GitHub';
let descripcion = 'Evento ' + (event || 'desconocido') + ' en ' + repo + '.';
let url = body.repository?.html_url || null;
let branch = null;
let prNumber = null;
let entityType = 'repository';
let entityId = repo;
let commitSha = body.after || body.head_commit?.id || body.pull_request?.head?.sha || null;
let occurredAt = body.pull_request?.updated_at || body.pull_request?.created_at || body.head_commit?.timestamp || new Date().toISOString();
let externalId = deliveryId || commitSha || repo + ':' + event + ':' + action;

if (event === 'pull_request') {
  const pr = body.pull_request || {};
  prNumber = body.number || pr.number || null;
  const prTitle = pr.title || 'PR sin titulo';
  url = pr.html_url || url;
  entityType = 'pull_request';
  entityId = String(prNumber || pr.id || repo + ':pr');
  commitSha = pr.head?.sha || commitSha;
  occurredAt = pr.updated_at || pr.merged_at || pr.closed_at || pr.created_at || occurredAt;
  externalId = deliveryId || String(pr.id || prNumber || commitSha || repo + ':pr');

  if (action === 'opened' || action === 'reopened') {
    tipo = 'github_pr_opened';
    titulo = 'PR abierto';
    descripcion = actor + ' abrio PR #' + prNumber + ' en ' + repo + ': ' + prTitle + '.';
  } else if (action === 'ready_for_review') {
    tipo = 'github_pr_ready';
    titulo = 'PR listo para revision';
    descripcion = actor + ' marco PR #' + prNumber + ' en ' + repo + ' listo para revision.';
  } else if (action === 'synchronize') {
    tipo = 'github_pr_updated';
    titulo = 'PR actualizado';
    descripcion = actor + ' actualizo PR #' + prNumber + ' en ' + repo + ': ' + prTitle + '.';
  } else if (action === 'closed' && pr.merged) {
    tipo = 'github_pr_merged';
    titulo = 'PR mergeado';
    descripcion = actor + ' mergeo PR #' + prNumber + ' en ' + repo + ': ' + prTitle + '.';
  } else if (action === 'closed') {
    tipo = 'github_pr_closed';
    titulo = 'PR cerrado';
    descripcion = actor + ' cerro PR #' + prNumber + ' en ' + repo + ': ' + prTitle + '.';
  } else {
    ignored = true;
    titulo = 'Evento GitHub ignorado';
    descripcion = 'Evento pull_request/' + action + ' no se procesa en este workflow.';
  }
} else if (event === 'pull_request_review') {
  const pr = body.pull_request || {};
  const review = body.review || {};
  prNumber = pr.number || body.number || null;
  const prTitle = pr.title || 'PR sin titulo';
  const reviewState = String(review.state || '').toLowerCase();
  url = review.html_url || pr.html_url || url;
  entityType = 'pull_request_review';
  entityId = String(review.id || prNumber || repo + ':review');
  commitSha = review.commit_id || pr.head?.sha || commitSha;
  occurredAt = review.submitted_at || pr.updated_at || occurredAt;
  externalId = deliveryId || String(review.id || pr.id || prNumber || commitSha || repo + ':review');

  if (reviewState === 'approved') {
    tipo = 'github_pr_review_approved';
    titulo = 'PR aprobado en review';
    descripcion = actor + ' aprobo PR #' + prNumber + ' en ' + repo + ': ' + prTitle + '.';
  } else if (reviewState === 'changes_requested') {
    tipo = 'github_pr_review_changes_requested';
    titulo = 'Cambios solicitados en PR';
    descripcion = actor + ' pidio cambios en PR #' + prNumber + ' en ' + repo + ': ' + prTitle + '.';
  } else {
    ignored = true;
    tipo = 'github_pr_review_ignored';
    titulo = 'Review de PR ignorada';
    descripcion = 'Review ' + (reviewState || 'sin estado') + ' del PR #' + prNumber + ' no requiere accion del hub.';
  }
} else if (event === 'push') {
  const ref = body.ref || '';
  branch = ref.replace('refs/heads/', '') || ref;
  const commits = Array.isArray(body.commits) ? body.commits : [];
  const commitCount = commits.length;
  url = body.compare || url;
  entityType = 'branch';
  entityId = branch || repo;
  occurredAt = body.head_commit?.timestamp || body.repository?.updated_at || occurredAt;
  externalId = deliveryId || String(body.after || ref || repo + ':push');

  if (branch === 'main' || branch === 'master') {
    ignored = true;
    tipo = 'github_push_main_ignored';
    titulo = 'Push principal ignorado';
    descripcion = actor + ' hizo push a ' + branch + ' en ' + repo + ' (' + commitCount + ' commits). Lo gestiona Construir Contexto Robusto.';
  } else {
    tipo = 'github_push_branch';
    titulo = 'Push en rama de trabajo';
    descripcion = actor + ' hizo push a ' + branch + ' en ' + repo + ' (' + commitCount + ' commits).';
  }
} else {
  ignored = true;
  titulo = 'Evento GitHub ignorado';
  descripcion = 'Evento ' + (event || 'desconocido') + ' no se procesa en este workflow.';
}

const eventId = deliveryId
  ? 'gh:' + deliveryId
  : 'gh:' + [repoScope, tipo, externalId, action || 'na'].filter(Boolean).join(':').replace(/[^a-zA-Z0-9:_-]/g, '_');
const correlationId = 'evt_' + eventId.replace(/[^a-zA-Z0-9_-]/g, '_').slice(0, 90);

const detalle = {
  event,
  action,
  repo,
  repo_name: repoName || null,
  repo_scope: repoScope,
  actor,
  branch,
  pr_number: prNumber,
  commit_sha: commitSha,
  url,
  event_id: eventId,
  correlation_id: correlationId,
  occurred_at: occurredAt,
  received_at: new Date().toISOString(),
  review_state: body.review?.state || null
};

const discord_content = '[PetSafe/GitHub/' + repoScope + '] ' + titulo + '\n' + descripcion + (url ? '\n' + url : '');
const normalized = {
  source: 'github',
  event_type: tipo,
  event,
  action,
  repo,
  repo_scope: repoScope,
  actor,
  entity_type: entityType,
  entity_id: entityId,
  pull_request_number: prNumber,
  commit_sha: commitSha,
  branch,
  occurred_at: occurredAt,
  url,
  review_state: body.review?.state || null,
  ignored
};

return [{
  json: {
    source: 'github',
    ignored,
    tipo,
    titulo,
    descripcion,
    detalle,
    detalle_json: JSON.stringify(detalle || {}),
    normalized_json: JSON.stringify(normalized || {}),
    raw_payload_json: JSON.stringify({ headers, body }),
    discord_content,
    event_id: eventId,
    external_id: String(externalId || eventId),
    occurred_at: occurredAt,
    correlation_id: correlationId,
    actor,
    entity_type: entityType,
    entity_id: entityId,
    repo,
    trello_card_id: null,
    pull_request_number: prNumber,
    commit_sha: commitSha
  }
}];
